m365-243.implementationNotes:
# Check Defender for Cloud status across all subscriptions
Connect-AzAccount
$subs = Get-AzSubscription
foreach ($sub in $subs) {
  Set-AzContext -SubscriptionId $sub.Id | Out-Null
  $pricings = Get-AzSecurityPricing
  $free = $pricings | Where-Object { $_.PricingTier -eq 'Free' }
  $standard = $pricings | Where-Object { $_.PricingTier -eq 'Standard' }
  Write-Host "`n=== $($sub.Name) ==="
  Write-Host "  Standard: $($standard.Count) plans, Free: $($free.Count) plans"
  $free | ForEach-Object { Write-Warning "  NOT ENABLED: $($_.Name)" }
}

# Enable Defender on a subscription
# Set-AzSecurityPricing -Name 'VirtualMachines' -PricingTier 'Standard'

m365-244.implementationNotes:
# Enable Defender for Servers Plan 2
Set-AzSecurityPricing -Name 'VirtualMachines' -PricingTier 'Standard' -SubPlan 'P2'

# Verify MDE agent deployment on VMs
Get-AzVM | ForEach-Object {
  $ext = Get-AzVMExtension -ResourceGroupName $_.ResourceGroupName -VMName $_.Name -Name 'MDE.Windows' -ErrorAction SilentlyContinue
  [PSCustomObject]@{
    VM = $_.Name
    RG = $_.ResourceGroupName
    MDEInstalled = [bool]$ext
    ProvisioningState = $ext.ProvisioningState
  }
} | Format-Table

# Enable JIT access
$jitPolicy = @{
  kind = 'Basic'
  properties = @{
    virtualMachines = @(@{
      id = '/subscriptions/<sub>/resourceGroups/<rg>/providers/Microsoft.Compute/virtualMachines/<vm>'
      ports = @(@{ number = 22; protocol = '*'; allowedSourceAddressPrefix = '*'; maxRequestAccessDuration = 'PT3H' })
    })
  }
}
